| dates.js | parseIso() | BAD_DATE | not an ISO date |
| format.js | padLeft() | BAD_WIDTH | width must be positive |
| money.js | toCents() | NEG_AMOUNT | amount below zero |
| parse.js | parseIntStrict() | BAD_INT | not an integer |
